import React from 'react';


const Project = ({name, desc, img}) => {
  return(
      <a className="works-item smooth-leave" href="booklandia.html">
        <div className="picture">
          <div className="content">
            <div className="text">
              <h2>{name}</h2>
              <ul>
                <li>{desc}</li>
              </ul>
            </div>
          </div>
          <img src={img} alt="" />
        </div>
      </a>
  );
}

export default Project
